const DVZ_LEGACY_SRGB_BLEND: bool = false;
// Shared transform pipeline for builtin scene vertex shaders.
//
// Bind group layout (group 0):
//   binding 0: MVP { model, view, proj, time, flags }
//   binding 1: Viewport { x, y, width, height }

struct MVP {
    model: mat4x4f,
    view: mat4x4f,
    proj: mat4x4f,
    time: f32,
    flags: u32,
}

struct Viewport {
    rect: vec4f,
}

@group(0) @binding(0) var<uniform> mvp: MVP;
@group(0) @binding(1) var<uniform> viewport: Viewport;

fn transform(position: vec3f) -> vec4f {
    return mvp.proj * mvp.view * mvp.model * vec4f(position, 1.0);
}


struct VertexIn {
    @location(0) position: vec3f,
    @location(1) color: vec4f,
    @location(2) radius: f32,
}

struct VertexOut {
    @builtin(position) position: vec4f,
    @location(0) color: vec4f,
    @location(1) center_view: vec4f,
    @location(2) radius: f32,
    @location(3) sprite_scale: f32,
    @location(4) coord: vec2f,
}

fn transform_radius(radius: f32) -> f32 {
    let sx = length(mvp.model[0].xyz);
    let sy = length(mvp.model[1].xyz);
    let sz = length(mvp.model[2].xyz);
    return radius * max(max(sx, sy), sz);
}

fn quad_corner(vertex_id: u32) -> vec2f {
    let corners = array<vec2f, 6>(
        vec2f(-1.0, -1.0),
        vec2f( 1.0, -1.0),
        vec2f(-1.0,  1.0),
        vec2f(-1.0,  1.0),
        vec2f( 1.0, -1.0),
        vec2f( 1.0,  1.0),
    );
    return corners[vertex_id];
}

@vertex
fn main(@builtin(vertex_index) vertex_id: u32, input: VertexIn) -> VertexOut {
    let corner = quad_corner(vertex_id);
    let center_view = mvp.view * mvp.model * vec4f(input.position, 1.0);
    let center = transform(input.position);
    let radius = max(transform_radius(input.radius), 1e-6);
    let inv_w = 1.0 / max(abs(center.w), 1e-6);
    let ndc_radius_data = vec2f(
        radius * abs(mvp.proj[0][0]) * inv_w,
        radius * abs(mvp.proj[1][1]) * inv_w,
    );
    let radius_px = 0.5 * max(
        ndc_radius_data.x * viewport.rect.z,
        ndc_radius_data.y * viewport.rect.w,
    );
    let padded_radius_px = radius_px + 1.5;
    let ndc_radius = ndc_radius_data + vec2f(
        3.0 / max(viewport.rect.z, 1.0),
        3.0 / max(viewport.rect.w, 1.0),
    );

    var output: VertexOut;
    output.position = vec4f(center.xy + corner * ndc_radius * center.w, center.zw);
    output.color = input.color;
    output.center_view = center_view;
    output.radius = radius;
    output.sprite_scale = padded_radius_px / max(radius_px, 1e-6);
    output.coord = corner * output.sprite_scale;
    return output;
}

const DVZ_LEGACY_SRGB_BLEND: bool = false;
// Shared transform pipeline for builtin scene vertex shaders.
//
// Bind group layout (group 0):
//   binding 0: MVP { model, view, proj, time, flags }
//   binding 1: Viewport { x, y, width, height }

struct MVP {
    model: mat4x4f,
    view: mat4x4f,
    proj: mat4x4f,
    time: f32,
    flags: u32,
}

struct Viewport {
    rect: vec4f,
}

@group(0) @binding(0) var<uniform> mvp: MVP;
@group(0) @binding(1) var<uniform> viewport: Viewport;

fn transform(position: vec3f) -> vec4f {
    return mvp.proj * mvp.view * mvp.model * vec4f(position, 1.0);
}

fn dvz_inverse_mat3x3f(m: mat3x3f) -> mat3x3f {
    let c0 = cross(m[1], m[2]);
    let c1 = cross(m[2], m[0]);
    let c2 = cross(m[0], m[1]);
    let inv_det = 1.0 / dot(m[0], c0);
    return transpose(mat3x3f(c0 * inv_det, c1 * inv_det, c2 * inv_det));
}

fn dvz_affine_inverse_translation(m: mat4x4f) -> vec3f {
    let linear = mat3x3f(m[0].xyz, m[1].xyz, m[2].xyz);
    return -(dvz_inverse_mat3x3f(linear) * m[3].xyz);
}

fn camera_position_from_view() -> vec3f {
    return dvz_affine_inverse_translation(mvp.view);
}

fn srgb_to_linear(srgb: vec3f) -> vec3f {
    let clipped = clamp(srgb, vec3f(0.0), vec3f(1.0));
    let lo = clipped / vec3f(12.92);
    let hi = pow((clipped + vec3f(0.055)) / vec3f(1.055), vec3f(2.4));
    return select(hi, lo, clipped <= vec3f(0.04045));
}

fn semantic_color_to_linear(color: vec4f) -> vec4f {
    let clipped = clamp(color.rgb, vec3f(0.0), vec3f(1.0));
    if (DVZ_LEGACY_SRGB_BLEND) {
        return vec4f(clipped, clamp(color.a, 0.0, 1.0));
    }
    return vec4f(srgb_to_linear(clipped), clamp(color.a, 0.0, 1.0));
}

fn sampled_texture_color_to_linear(color: vec4f, params: vec4f) -> vec4f {
    if (params.x > 0.5) {
        return semantic_color_to_linear(color);
    }
    return vec4f(color.rgb, clamp(color.a, 0.0, 1.0));
}

struct SceneMaterial {
    light_direction: vec4f,
    params: vec4f,
    model: vec4f,
    base_color_factor: vec4f,
    standard_params: vec4f,
    emissive_rim: vec4f,
    depth_cue: vec4f,
    depth_cue_color: vec4f,
    depth_cue_extra: vec4f,
}

@group(1) @binding(0) var<uniform> material: SceneMaterial;

fn evaluate_scene_material_linear_item(
    linear_item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    let model = i32(material.model.x + 0.5);
    let opacity = clamp(material.model.y, 0.0, 1.0);
    let linear_base_color = semantic_color_to_linear(material.base_color_factor);
    let emissive = srgb_to_linear(material.emissive_rim.rgb);
    let base = linear_item_color.rgb * linear_base_color.rgb;
    let alpha = linear_item_color.a * linear_base_color.a * opacity;
    if (model == 0) {
        return vec4f(clamp(base + emissive, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let n = normalize(normal);
    let l = normalize(material.light_direction.xyz);
    let v = normalize(camera_position - world_position);
    let h = normalize(l + v);
    let lambert = max(dot(n, l), 0.0);
    if (model == 2) {
        let roughness = clamp(material.standard_params.x, 0.0, 1.0);
        let specular_strength = max(material.standard_params.y, 0.0);
        let metallic = clamp(material.standard_params.z, 0.0, 1.0);
        let rim_strength = max(material.standard_params.w, 0.0);
        let shininess = max(1.0, 128.0 * (1.0 - roughness) + 1.0);
        let specular = pow(max(dot(n, h), 0.0), shininess) * specular_strength;
        let rim = pow(1.0 - max(dot(n, v), 0.0), 2.0) * rim_strength;
        let diffuse = base * (0.04 + (1.0 - metallic) * lambert);
        let rgb = diffuse + vec3f(specular + rim) + emissive;
        return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
    }

    let specular = pow(max(dot(n, h), 0.0), max(material.params.w, 1.0));
    let rgb = base * (material.params.x + material.params.y * lambert) +
        vec3f(material.params.z * specular);
    return vec4f(clamp(rgb, vec3f(0.0), vec3f(1.0)), alpha);
}

fn evaluate_scene_material(
    item_color: vec4f,
    normal: vec3f,
    world_position: vec3f,
    camera_position: vec3f,
) -> vec4f {
    return evaluate_scene_material_linear_item(
        semantic_color_to_linear(item_color), normal, world_position, camera_position);
}

fn depth_cue_coordinate(cue: vec3f) -> f32 {
    let metric = i32(material.depth_cue_extra.x + 0.5);
    if (metric == 1) {
        return cue.y;
    }
    if (metric == 2) {
        return cue.z;
    }
    return cue.x;
}

fn depth_cue_factor(cue: vec3f) -> f32 {
    let strength = clamp(material.depth_cue.z, 0.0, 1.0);
    let mode = i32(material.depth_cue.w + 0.5);
    if (mode == 0 || strength <= 0.0) {
        return 0.0;
    }

    let denom = max(material.depth_cue.y - material.depth_cue.x, 1e-6);
    let coord = depth_cue_coordinate(cue);
    var t = clamp((coord - material.depth_cue.x) / denom, 0.0, 1.0);
    let falloff = i32(material.depth_cue_extra.y + 0.5);
    if (falloff == 1) {
        let density = max(material.depth_cue_extra.z, 1e-6);
        t = (1.0 - exp(-density * t)) / max(1.0 - exp(-density), 1e-6);
    }
    return t * strength;
}

fn apply_depth_cue(rgb: vec3f, cue: vec3f) -> vec3f {
    let mode = i32(material.depth_cue.w + 0.5);
    let t = depth_cue_factor(cue);
    if (t <= 0.0) {
        return rgb;
    }
    if (mode == 1) {
        return mix(rgb, srgb_to_linear(material.depth_cue_color.rgb), t);
    }
    if (mode == 2) {
        let luma = dot(rgb, vec3f(0.2126, 0.7152, 0.0722));
        return mix(rgb, vec3f(luma), t);
    }
    if (mode == 3) {
        return mix(rgb, vec3f(0.0), t);
    }
    return rgb;
}


struct FragmentIn {
    @location(0) color: vec4f,
    @location(1) center_view: vec4f,
    @location(2) radius: f32,
    @location(3) sprite_scale: f32,
    @location(4) coord: vec2f,
}

struct FragmentOut {
    @builtin(frag_depth) depth: f32,
    @location(0) color: vec4f,
}

fn coverage_threshold(position: vec4f) -> f32 {
    return fract(52.9829189 * fract(0.06711056 * position.x + 0.00583715 * position.y));
}

fn project_depth(view_position: vec4f) -> vec4f {
    var clip = mvp.proj * view_position;
    clip.y = -clip.y;
    clip.z = 0.5 * (clip.z + clip.w);
    return clip;
}

fn raycast_sphere(coord: vec2f, center_view: vec4f, radius: f32) -> vec4f {
    let ortho = abs(mvp.proj[3][3]) > 0.5;
    var ro = vec3f(0.0);
    var rd = vec3f(0.0, 0.0, -1.0);
    let plane_point = center_view.xyz + vec3f(coord.x * radius, coord.y * radius, 0.0);
    if (ortho) {
        ro = plane_point + vec3f(0.0, 0.0, radius);
    } else {
        rd = normalize(plane_point);
    }

    let oc = ro - center_view.xyz;
    let b = dot(oc, rd);
    let c = dot(oc, oc) - radius * radius;
    let h = b * b - c;
    if (h < 0.0) {
        return vec4f(0.0);
    }
    let t = -b - sqrt(h);
    if (t <= 0.0) {
        return vec4f(0.0);
    }
    return vec4f(ro + t * rd, 1.0);
}

fn view_to_world_position(view_position: vec3f) -> vec3f {
    let linear = mat3x3f(mvp.view[0].xyz, mvp.view[1].xyz, mvp.view[2].xyz);
    let inv_linear = dvz_inverse_mat3x3f(linear);
    return inv_linear * (view_position - mvp.view[3].xyz);
}

fn view_to_world_direction(view_direction: vec3f) -> vec3f {
    let linear = mat3x3f(mvp.view[0].xyz, mvp.view[1].xyz, mvp.view[2].xyz);
    return dvz_inverse_mat3x3f(linear) * view_direction;
}

@fragment
fn main(input: FragmentIn, @builtin(position) frag_position: vec4f) -> FragmentOut {
    let coord = vec2f(input.coord.x, -input.coord.y);
    let dist = length(coord);
    let coverage = clamp((1.0 - dist) / max(fwidth(dist), 1e-6) + 0.5, 0.0, 1.0);
    if (coverage <= coverage_threshold(frag_position)) {
        discard;
    }

    let surface_coord = select(coord, coord / max(dist, 1e-6), dist > 1.0);
    let edge = 1.0 - dot(surface_coord, surface_coord);
    var normal_view = normalize(vec3f(surface_coord, sqrt(max(edge, 0.0))));
    var surface_view = input.center_view + vec4f(normal_view * input.radius, 0.0);
    let mode = i32(material.depth_cue_extra.w + 0.5);
    if (mode == 1) {
        surface_view = raycast_sphere(surface_coord, input.center_view, input.radius);
        if (surface_view.w == 0.0) {
            discard;
        }
        normal_view = normalize(surface_view.xyz - input.center_view.xyz);
    }

    let depth_clip = project_depth(surface_view);
    let depth = clamp(depth_clip.z / max(abs(depth_clip.w), 1e-6), 0.0, 1.0);
    let world_position = view_to_world_position(surface_view.xyz);
    let camera_position = camera_position_from_view();
    let normal_world = normalize(view_to_world_direction(normal_view));
    let shaded = evaluate_scene_material(input.color, normal_world, world_position, camera_position);
    let cue = vec3f(depth, length(camera_position - world_position), length(world_position));
    let color = vec4f(apply_depth_cue(shaded.rgb, cue), shaded.a);
    if (color.a <= 0.0) {
        discard;
    }
    return FragmentOut(depth, color);
}

